      repeat_rule: item.repeatRule || 'none',
      repeat_interval: item.repeatRule === 'biweekly' ? 2 : 1,
      notify_before_hours: item.notifyBeforeHours === '' || item.notifyBeforeHours === undefined ? 12 : Number(item.notifyBeforeHours),
